CREATE TABLE IF NOT EXISTS "ProjectRecord" (
  id              TEXT PRIMARY KEY,
  sno             INTEGER NOT NULL DEFAULT 0,
  "customerName"   TEXT NOT NULL DEFAULT '',
  "voltageLevel"   TEXT NOT NULL DEFAULT '',
  industry        TEXT NOT NULL DEFAULT '',
  "scopeOfWork"    TEXT NOT NULL DEFAULT '',
  location        TEXT NOT NULL DEFAULT '',
  state           TEXT NOT NULL DEFAULT '',
  "projectValue"   TEXT NOT NULL DEFAULT '',
  year            TEXT NOT NULL DEFAULT '',
  active          BOOLEAN NOT NULL DEFAULT TRUE,
  "createdAt"     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  "updatedAt"     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS "ProjectRecord_industry_idx" ON "ProjectRecord" (industry);
CREATE INDEX IF NOT EXISTS "ProjectRecord_state_idx" ON "ProjectRecord" (state);
CREATE INDEX IF NOT EXISTS "ProjectRecord_year_idx" ON "ProjectRecord" (year);

